import React from "react";
import { useParams } from "react-router-dom";
import {
  Container,
  Typography,
  Grid,
  Paper,
  Avatar,
  Divider,
  List,
  ListItem,
  ListItemText,
  Button,
  Box,
} from "@mui/material";

import { doctors } from "../data/doctors"; // fixed import

const DoctorProfile = () => {
  const { doctorId } = useParams(); // ← must be INSIDE the component

  const doctor = doctors.find((d) => d.id === Number(doctorId));

  if (!doctor) {
    return (
      <Container sx={{ py: 8 }}>
        <Typography variant="h5" align="center" color="error">
          Doctor not found
        </Typography>
      </Container>
    );
  }

  return (
    <Container
      maxWidth="xl" // full wide page
      sx={{
        py: 12, // lots of top/bottom space
        px: { xs: 3, md: 8, lg: 12 }, // generous side padding
        minHeight: "90vh", // almost full viewport height
      }}
    >
      <Paper
        elevation={6}
        sx={{
          p: { xs: 5, md: 10 }, // MUCH bigger internal padding
          borderRadius: 4,
          maxWidth: 1400, // very wide card (adjust down to 1200 if too big)
          mx: "auto", // center it
          backgroundColor: "#ffffff",
          boxShadow: "0 16px 60px rgba(0,0,0,0.15)", // strong shadow
        }}
      >
        <Grid container spacing={8}>
          {" "}
          // more breathing room between sections
          {/* LEFT - Photo section (wider now) */}
          <Grid
            item
            xs={12}
            md={5} // 5/12 = wider photo area
            sx={{
              textAlign: "center",
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              justifyContent: "center",
            }}
          >
            <Avatar
              src={doctor.image}
              alt={doctor.name}
              sx={{
                width: { xs: 260, md: 420, lg: 480 }, // very large photo
                height: { xs: 260, md: 420, lg: 480 },
                mb: 5,
                border: "8px solid #e8f4fd",
                boxShadow: 8,
              }}
            />
            <Typography
              variant="h3"
              sx={{
                fontWeight: "bold",
                mb: 1,
                fontSize: { xs: "2rem", md: "3rem" },
              }}
            >
              {doctor.name}
            </Typography>
            <Typography variant="h4" color="primary" sx={{ mb: 4 }}>
              {doctor.specialty}
            </Typography>
          </Grid>
          {/* RIGHT - Details section (wider now) */}
          <Grid item xs={12} md={7}>
            <Typography
              variant="h4"
              sx={{
                mb: 5,
                fontWeight: 600,
                color: "#1976d2",
              }}
            >
              Professional Details
            </Typography>

            <Divider sx={{ mb: 5, borderColor: "#1976d2", borderWidth: 2 }} />

            <List disablePadding>
              <ListItem sx={{ py: 3 }}>
                <ListItemText
                  primary={
                    <Typography variant="h6" sx={{ fontSize: "1.4rem" }}>
                      Experience
                    </Typography>
                  }
                  secondary={
                    <Typography variant="body1" sx={{ fontSize: "1.25rem" }}>
                      {doctor.experience}
                    </Typography>
                  }
                />
              </ListItem>

              <ListItem sx={{ py: 3 }}>
                <ListItemText
                  primary={
                    <Typography variant="h6" sx={{ fontSize: "1.4rem" }}>
                      Qualification
                    </Typography>
                  }
                  secondary={
                    <Typography variant="body1" sx={{ fontSize: "1.25rem" }}>
                      {doctor.qualification}
                    </Typography>
                  }
                />
              </ListItem>

              <ListItem sx={{ py: 3 }}>
                <ListItemText
                  primary={
                    <Typography variant="h6" sx={{ fontSize: "1.4rem" }}>
                      Availability
                    </Typography>
                  }
                  secondary={
                    <Typography variant="body1" sx={{ fontSize: "1.25rem" }}>
                      {doctor.availability}
                    </Typography>
                  }
                />
              </ListItem>

              <ListItem sx={{ py: 3, alignItems: "flex-start" }}>
                <ListItemText
                  primary={
                    <Typography variant="h6" sx={{ fontSize: "1.4rem" }}>
                      About
                    </Typography>
                  }
                  secondary={
                    <Typography
                      variant="body1"
                      sx={{
                        fontSize: "1.25rem",
                        lineHeight: 1.8,
                        color: "#424242",
                      }}
                    >
                      {doctor.bio}
                    </Typography>
                  }
                />
              </ListItem>
            </List>

            <Box sx={{ mt: 10, textAlign: "center" }}>
              <Button
                variant="contained"
                color="primary"
                size="large"
                sx={{
                  py: 3,
                  px: 10,
                  fontSize: "1.4rem",
                  borderRadius: 3,
                  boxShadow: 4,
                }}
              >
                Book Appointment
              </Button>
            </Box>
          </Grid>
        </Grid>
      </Paper>
    </Container>
  );
};

export default DoctorProfile;
